import{_ as p,c as r}from"./app.c70f1779.js";const n={},t=r('<h1 id="linux\u7CFB\u7EDF\u7CBE\u8BB2" tabindex="-1"><a class="header-anchor" href="#linux\u7CFB\u7EDF\u7CBE\u8BB2" aria-hidden="true">#</a> Linux\u7CFB\u7EDF\u7CBE\u8BB2</h1><h2 id="linux\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#linux\u7B80\u4ECB" aria-hidden="true">#</a> Linux\u7B80\u4ECB</h2><h3 id="\u7CFB\u7EDF\u4ECB\u7ECD" tabindex="-1"><a class="header-anchor" href="#\u7CFB\u7EDF\u4ECB\u7ECD" aria-hidden="true">#</a> \u7CFB\u7EDF\u4ECB\u7ECD</h3><p><img src="https://wqby-1304194722.cos.ap-nanjing.myqcloud.com/img/image-20230524115916655.png" alt="image-20230524115916655"></p><p>\u65CF\u8C31</p><p><img src="https://wqby-1304194722.cos.ap-nanjing.myqcloud.com/img/image-20230524115933548.png" alt="image-20230524115933548"></p><p>\u77E5\u540D\u7684Linux\u7CFB\u7EDF</p><p><img src="https://wqby-1304194722.cos.ap-nanjing.myqcloud.com/img/image-20230524115948261.png" alt="image-20230524115948261"></p><h3 id="\u4E3A\u4EC0\u4E48\u8981\u5B66\u4E60linux" tabindex="-1"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u8981\u5B66\u4E60linux" aria-hidden="true">#</a> \u4E3A\u4EC0\u4E48\u8981\u5B66\u4E60Linux</h3><p>Linux \u7CFB\u7EDF\u5728\u670D\u52A1\u5668\u5E02\u573A\u7684\u5360\u6709\u7387\uFF082016 \u5E74\uFF09</p><p><img src="https://wqby-1304194722.cos.ap-nanjing.myqcloud.com/img/image-20230524115811461.png" alt="image-20230524115811461"></p><p>\u4E16\u754C\u4E0A 500 \u4E2A\u6700\u5FEB\u7684\u8D85\u7EA7\u8BA1\u7B97\u673A 90\uFF05\u4EE5\u4E0A\u8FD0\u884C Linux \u53D1\u884C\u7248\u6216\u53D8\u79CD\uFF0C\u5305\u62EC\u6700\u5FEB\u7684\u524D 10\u540D\u8D85\u7EA7\u8BA1\u7B97\u673A\u8FD0\u884C\u7684\u90FD\u662F\u57FA\u4E8E Linux \u5185\u6838\u7684\u64CD\u4F5C\u7CFB\u7EDF\u3002Linux \u4E5F\u5E7F\u6CDB\u5E94\u7528\u5728\u5D4C\u5165\u5F0F\u7CFB\u7EDF\u4E0A\uFF0C\u5982\u624B\u673A\uFF08Mobile Phone\uFF09\u3001\u5E73\u677F\u7535\u8111\uFF08Tablet\uFF09\u3001\u8DEF\u7531\u5668\uFF08Router\uFF09\u3001\u7535\u89C6\uFF08TV\uFF09\u548C\u7535\u5B50\u6E38\u620F\u673A\u7B49\u3002\u5728\u79FB\u52A8\u8BBE\u5907\u4E0A\u5E7F\u6CDB\u4F7F\u7528\u7684 Android \u64CD\u4F5C\u7CFB\u7EDF\u5C31\u662F\u521B\u5EFA\u5728 Linux \u5185\u6838\u4E4B\u4E0A\u3002</p><h3 id="linux\u7684\u4F18\u70B9" tabindex="-1"><a class="header-anchor" href="#linux\u7684\u4F18\u70B9" aria-hidden="true">#</a> Linux\u7684\u4F18\u70B9</h3><ol><li>\u5F00\u6E90\u514D\u8D39\u3001\u53EF\u81EA\u884C\u4FEE\u6539\uFF0C\u5BF9\u5176\u4ED6\u5F00\u6E90\u8F6F\u4EF6\u517C\u5BB9\u6027\u826F\u597D</li><li>\u591A\u7528\u6237\u8BBF\u95EE\u53CB\u597D\u3001\u6743\u9650\u7BA1\u7406\u65B9\u4FBF\u5FEB\u6377</li><li>\u5185\u5B58\u7BA1\u7406\u4F18\u79C0\uFF0C\u53EF\u4EE5\u957F\u671F\u8FDE\u7EED\u8FD0\u884C\uFF0C\u7CFB\u7EDF\u5360\u7528\u5185\u5B58\u4F4E</li><li>\u5DE5\u5177\u529F\u80FD\u5E93\u5B8C\u5584\uFF0C\u90E8\u7F72\u5B89\u88C5\u65B9\u4FBF</li></ol><h2 id="linux\u57FA\u672C\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#linux\u57FA\u672C\u547D\u4EE4" aria-hidden="true">#</a> Linux\u57FA\u672C\u547D\u4EE4</h2><h3 id="ls\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#ls\u547D\u4EE4" aria-hidden="true">#</a> ls\u547D\u4EE4</h3><p>\u547D\u4EE4 ls \u662F list \u7684\u7F29\u5199</p><p>\u5176\u4F5C\u7528\u662F\u5217\u51FA\u6307\u5B9A\u4F4D\u7F6E\u7684\u6587\u4EF6\u548C\u6587\u4EF6\u5939</p><p>\u5982\u679C\u6CA1\u6709\u6307\u5B9A\uFF0C\u9ED8\u8BA4\u662F\u5217\u51FA\u5F53\u524D\u4F4D\u7F6E\u7684\u6587\u4EF6\u6216\u8005\u6587\u4EF6\u5939</p><p>\u5E38\u7528\u7684\u53C2\u6570\u6709</p><p><strong>-a</strong> <strong>\u5217\u51FA\u6240\u6709\u7684\u6587\u4EF6\u6216\u8005\u6587\u4EF6\u5939</strong></p><p>\u5728 Linux \u7CFB\u7EDF\u91CC\u9762\uFF0C\u4EE5 . \u5F00\u5934\u7684\u6587\u4EF6\u6216\u8005\u6587\u4EF6\u5939\uFF0C\u4E00\u822C\u4F1A\u88AB\u9ED8\u8BA4\u89C6\u4E3A\u9690\u85CF\u7684\u5982\u679C\u60F3\u8981\u67E5\u770B\u8FD9\u4E9B\u9690\u85CF\u6587\u4EF6\u6216\u8005\u6587\u4EF6\u5939\uFF0C\u6700\u597D\u4F7F\u7528-a \u53C2\u6570</p><p><strong>-l</strong> <strong>\u5217\u51FA\u8BE6\u7EC6\u4FE1\u606F</strong></p><p>\u9ED8\u8BA4 ls \u53EA\u663E\u793A\u540D\u5B57\uFF0C\u5E76\u4E0D\u663E\u793A\u8BE6\u7EC6\u4FE1\u606F</p><p>\u52A0\u4E86\u8BE5\u53C2\u6570\u540E\uFF0C\u9664\u4E86\u4F1A\u663E\u793A\u540D\u79F0\u4EE5\u5916\uFF0C\u8FD8\u4F1A\u663E\u793A\u6587\u4EF6\u7684\u6743\u9650\u3001\u6240\u5C5E\u7528\u6237\u3001\u5206\u7EC4\u3001\u5927\u5C0F\u3001\u4FEE\u6539</p><p>\u65E5\u671F</p><p><strong>-h</strong> <strong>\u589E\u52A0\u53EF\u8BFB\u6027</strong></p><p>\u9ED8\u8BA4\u6587\u4EF6\u662F\u6309\u7167\u5B57\u8282\u4E3A\u5355\u4F4D\u663E\u793A\u5927\u5C0F\u7684</p><p>\u52A0\u4E86\u8FD9\u4E2A\u53C2\u6570\u540E\uFF0C\u4F1A\u9644\u5E26 K\u3001M\u3001G\u3001T \u7B49\u5927\u5C0F\u540E\u7F00</p><p>K \u8868\u793A\u5343\u5B57\u8282 M \u8868\u793A\u5146\u5B57\u8282 G \u8868\u793A 1024 \u5146 T \u8868\u793A 1024G</p><p>\u867D\u7136\u7CBE\u51C6\u5EA6\u4E0B\u964D\u4E86\uFF0C\u4F46\u662F\u66F4\u5BB9\u6613\u9605\u8BFB</p><p><strong>-R</strong> <strong>\u9012\u5F52\u8BBF\u95EE</strong></p><p>\u9ED8\u8BA4\u662F\u663E\u793A\u5F53\u524D\u76EE\u5F55\u4E0B\u7684\u6587\u4EF6\u548C\u6587\u4EF6\u5939</p><p>\u5E26\u4E0A R \u53C2\u6570\u540E\uFF0C\u5982\u679C\u5F53\u524D\u76EE\u5F55\u4E0B\u6709\u5176\u4ED6\u6587\u4EF6\u5939</p><p>\u5219\u4F1A\u5C06\u8BE5\u6587\u4EF6\u5939\u4E0B\u9762\u7684\u6587\u4EF6\u548C\u6587\u4EF6\u5939\u4E5F\u663E\u793A\u51FA\u6765</p><p>\u6240\u4EE5\u8BE5\u53C2\u6570\u4F1A\u663E\u793A\u6307\u5B9A\u4F4D\u7F6E\u4E0B\u7684\u6240\u6709\u6587\u4EF6\u548C\u6587\u4EF6\u5939</p><p><strong>-Q</strong> <strong>\u6587\u4EF6\u540D\u7528\u53CC\u5F15\u53F7\u5305\u88F9</strong></p><p>\u8FD9\u4E2A\u53C2\u6570\u662F\u4E3A\u4E86\u9632\u6B62\u67D0\u4E9B\u6587\u4EF6\u6216\u8005\u6587\u4EF6\u5939\u7684\u672B\u5C3E\u662F\u7A7A\u683C\u5B57\u7B26</p><p>\u8FD9\u6837\uFF0C\u53EF\u4EE5\u901A\u8FC7\u53CC\u5F15\u53F7\uFF0C\u770B\u5230\u6587\u4EF6\u540D\u5B9E\u9645\u7684\u957F\u5EA6</p><h3 id="echo\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#echo\u547D\u4EE4" aria-hidden="true">#</a> echo\u547D\u4EE4</h3><p><strong>\u663E\u793A\u5B57\u7B26\u4E32</strong></p><p>echo hello world</p><p>\u6216\u8005 echo \u201Chello world\u201D</p><p><strong>\u663E\u793A\u8F6C\u4E49\u5B57\u7B26</strong></p><p>echo \\\u201D \u6216\u8005 \\\u2019 \\`</p><p><strong>\u663E\u793A\u53D8\u91CF</strong></p><p>echo $PATH</p><p><strong>\u663E\u793A\u6362\u884C</strong> \\ <strong>\u4E0D\u6362\u884C</strong></p><p>echo -e \u201C\\n\u201D\u6362\u884C</p><p>echo -e \u201C\\c\u201D\u4E0D\u6362\u884C</p><p><strong>\u663E\u793A\u539F\u6837\u5B57\u7B26\u4E32</strong></p><p>echo &#39;$PATH&#39;</p><p><strong>\u663E\u793A\u547D\u4EE4\u7ED3\u679C</strong></p><p>echo <code>data</code></p><h3 id="cd\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#cd\u547D\u4EE4" aria-hidden="true">#</a> cd\u547D\u4EE4</h3><p>cd \u76EE\u6807\u8DEF\u5F84</p><p>change directory</p><p>\u8DEF\u5F84\u53EF\u4EE5\u662F\u7EDD\u5BF9\u8DEF\u5F84\uFF0C\u4E5F\u53EF\u4EE5\u662F\u76F8\u5BF9\u8DEF\u5F84\u9664\u6B64\u4E4B\u5916\uFF0C\u8FD8\u6709\u4E00\u4E9B\u7279\u522B\u7684\u7B26\u53F7</p><p>\u6BD4\u5982.\u8868\u793A\u5F53\u524D\u76EE\u5F55</p><p>\u6BD4\u5982..\u8868\u793A\u4E0A\u4E00\u7EA7\u76EE\u5F55\uFF08\u4E5F\u5C31\u662F\u7236\u76EE\u5F55\uFF09</p><p>\u6BD4\u5982~\u8868\u793A\u5F53\u524D\u7528\u6237\u7684\u7528\u6237\u76EE\u5F55</p><p>\u6CE8\u610F\u5728 root \u7528\u6237\u548C\u666E\u901A\u7528\u6237\u6761\u4EF6\u4E0B\uFF0C\u8FD9\u4E2A\u7B26\u53F7\u662F\u6709\u4E0D\u540C\u542B\u4E49\u7684</p><p>\u666E\u901A\u7528\u6237~\u4E00\u822C\u662F/home/\u7528\u6237\u540D\u6587\u4EF6\u5939</p><p>\u4F46\u662F root \u7528\u6237\u5BF9\u5E94\u7684~\u662F/root \u6587\u4EF6\u5939</p><h3 id="head\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#head\u547D\u4EE4" aria-hidden="true">#</a> head\u547D\u4EE4</h3><p><strong>-c n</strong> <strong>\u663E\u793A\u5934\u90E8\u7684\u6307\u5B9A</strong> <strong>n</strong> <strong>\u4E2A\u5B57\u7B26</strong></p><p><strong>-n x</strong> <strong>\u663E\u793A\u5934\u90E8\u7684\u6307\u5B9A\u7684</strong> <strong>x</strong> <strong>\u884C</strong></p><p><strong>-v</strong> <strong>\u663E\u793A\u6587\u4EF6\u540D</strong></p><p><strong>-q</strong> <strong>\u4E0D\u663E\u793A\u6587\u4EF6\u540D\uFF08\u9ED8\u8BA4\uFF09</strong></p><h3 id="tail\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#tail\u547D\u4EE4" aria-hidden="true">#</a> tail\u547D\u4EE4</h3><p>\u7B80\u5355\u547D\u4EE4</p><p>\u663E\u793A\u5F53\u524D\u76EE\u5F55 pwd</p><p>\u6E05\u7A7A\u7A97\u53E3 clear</p><p>**&gt;**\u5C06\u5DE6\u8FB9\u547D\u4EE4\u7684\u8F93\u51FA\uFF0C<strong>\u8F93\u5165</strong>\u5230\u53F3\u8FB9\u7684\u6587\u4EF6\u6216\u8005\u547D\u4EE4</p><p>\u5982\u679C\u53F3\u8FB9\u7684\u6587\u4EF6\u4E0D\u5B58\u5728\uFF0C\u5219\u521B\u5EFA\u4E00\u4E2A</p><p>**&gt;&gt;**\u5C06\u5DE6\u8FB9\u547D\u4EE4\u7684\u8F93\u51FA\uFF0C<strong>\u8FFD\u52A0</strong>\u5230\u53F3\u8FB9\u7684\u6587\u4EF6</p><p>\u5982\u679C\u53F3\u8FB9\u7684\u6587\u4EF6\u4E0D\u5B58\u5728\uFF0C\u5219\u521B\u5EFA\u4E00\u4E2A</p><p><strong>-f</strong> <strong>\u53EF\u4EE5\u4E0D\u65AD\u7684\u66F4\u65B0\u5C3E\u90E8\u5185\u5BB9</strong></p><p><strong>-n</strong> <strong>\u663E\u793A\u5C3E\u90E8\u6307\u5B9A\u884C\u6570\u7684\u5185\u5BB9</strong></p><p><strong>-c</strong> <strong>\u663E\u793A\u5C3E\u90E8\u6307\u5B9A\u5B57\u8282\u7684\u5185\u5BB9</strong></p><p><strong>-v</strong> <strong>\u663E\u793A\u6587\u4EF6\u540D</strong></p><p><strong>-q</strong> <strong>\u4E0D\u663E\u793A\u6587\u4EF6\u540D\uFF08\u9ED8\u8BA4\uFF09</strong></p><h3 id="ps\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#ps\u547D\u4EE4" aria-hidden="true">#</a> ps\u547D\u4EE4</h3><p>\u6240\u6709\u8FDB\u7A0B\u90FD\u662F init \u8FDB\u7A0B\u7684\u5B50\u8FDB\u7A0B\u6216\u8005\u5B59\u8FDB\u7A0B</p><p><strong>-Al</strong> <strong>\u663E\u793A\u6240\u6709\u8FDB\u7A0B\u7684\u8BE6\u60C5\u548C\u8FDB\u7A0B\u540D\u79F0</strong></p><p><strong>-aux</strong> <strong>\u663E\u793A\u6240\u6709\u8FDB\u7A0B\u548C\u5176\u542F\u52A8\u547D\u4EE4</strong></p><p><strong>\u6570\u503C\u9879\u8BF4\u660E</strong></p><p>USER \u8FDB\u7A0B\u6240\u5C5E\u7528\u6237</p><p>UID \u8FDB\u7A0B\u6240\u5C5E\u7528\u6237 ID</p><p>PID \u8FDB\u7A0B ID</p><p>%CPU CPU \u5360\u7528\u7387</p><p>%MEM \u5185\u5B58\u5360\u7528\u7387</p><p>VSZ \u865A\u62DF\u5185\u5B58\u5360\u7528\u5927\u5C0F\uFF08\u5176\u4E2D\u90E8\u5206\u53EF\u80FD\u5728\u4EA4\u6362\u6587\u4EF6\u4E2D\uFF09</p><p>RSS \u5B9E\u9645\u5185\u5B58\u5360\u7528\u5927\u5C0F\uFF08RAM \u5360\u7528\u7684\u5927\u5C0F\uFF09</p><p>TTY \u5BF9\u5E94\u7684\u63A7\u5236\u53F0\u8BBE\u5907</p><p>TIME \u8FDB\u7A0B\u6267\u884C\u7684\u65F6\u95F4</p><p>START \u8FDB\u7A0B\u5F00\u59CB\u6267\u884C\u7684\u4E16\u754C</p><p>COMMAND \u8FDB\u7A0B\u542F\u52A8\u6267\u884C\u7684\u547D\u4EE4\uFF08\u5E26\u53C2\u6570\uFF09</p><p>CMD \u8FDB\u7A0B\u542F\u52A8\u6267\u884C\u7684\u547D\u4EE4\uFF08\u4E0D\u5E26\u53C2\u6570\uFF09</p><p>S/STAT \u72B6\u6001 S \u4F11\u7720 R \u8FD0\u884C D \u963B\u585E Z \u50F5\u5C38\u8FDB\u7A0B T \u6682\u505C</p><p>PRI \u4F18\u5148\u7EA7 \u6570\u503C\u8D8A\u4F4E\uFF0C\u4F18\u5148\u7EA7\u8D8A\u9AD8\uFF0C\u751A\u81F3\u53EF\u80FD\u4E3A\u8D1F\u6570</p><h3 id="cp\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#cp\u547D\u4EE4" aria-hidden="true">#</a> cp\u547D\u4EE4</h3><p>copy \u590D\u5236\u7684\u7F29\u5199</p><p>\u547D\u4EE4\u7528\u6CD5\uFF1Acp [\u53C2\u6570] \u6E90\u6587\u4EF6/\u6587\u4EF6\u5939 \u76EE\u6807\u6587\u4EF6/\u6587\u4EF6\u5939</p><p>[]\u8868\u793A\u53EF\u9009</p><p>sudo \u547D\u4EE4 \u63D0\u6743\uFF08\u63D0\u5347\u6743\u9650\uFF09mkdir \u521B\u5EFA\u6587\u4EF6\u5939</p><p><strong>-a\uFF1A\u5E26\u5C5E\u6027\u590D\u5236</strong></p><p>\u6B64\u9009\u9879\u901A\u5E38\u5728\u590D\u5236\u76EE\u5F55\u65F6\u4F7F\u7528\uFF0C\u5B83\u4FDD\u7559\u94FE\u63A5\u3001\u6587\u4EF6\u5C5E\u6027\uFF0C\u5E76\u590D\u5236\u76EE\u5F55\u4E0B\u7684\u6240\u6709\u5185\u5BB9\u3002\u5176\u4F5C\u7528</p><p>\u7B49\u4E8E dpR \u53C2\u6570\u7EC4\u5408\u3002</p><p><strong>-d</strong>\uFF1A\u590D\u5236\u65F6\u4FDD\u7559\u94FE\u63A5</p><p>\u8FD9\u91CC\u6240\u8BF4\u7684\u94FE\u63A5\u76F8\u5F53\u4E8E Windows \u7CFB\u7EDF\u4E2D\u7684\u5FEB\u6377\u65B9\u5F0F\u3002</p><p><strong>-f</strong>\uFF1A\u5F3A\u5236\u8986\u76D6</p><p>\u8986\u76D6\u5DF2\u7ECF\u5B58\u5728\u7684\u76EE\u6807\u6587\u4EF6\u800C\u4E0D\u7ED9\u51FA\u63D0\u793A</p><p>Ubuntu \u9ED8\u8BA4\u662F\u5F3A\u5236\u8986\u76D6</p><p><strong>-i</strong>\uFF1A\u8986\u76D6\u63D0\u793A</p><p>\u4E0E-f \u9009\u9879\u76F8\u53CD\uFF0C\u5728\u8986\u76D6\u76EE\u6807\u6587\u4EF6\u4E4B\u524D\u7ED9\u51FA\u63D0\u793A\uFF0C\u8981\u6C42\u7528\u6237\u786E\u8BA4\u662F\u5426\u8986\u76D6\uFF0C\u56DE\u7B54&quot;y&quot;\u65F6\u76EE\u6807\u6587</p><p>\u4EF6\u5C06\u88AB\u8986\u76D6\u3002</p><p><strong>-p</strong>\uFF1A\u5E26\u6743\u9650\u590D\u5236</p><p>\u9664\u590D\u5236\u6587\u4EF6\u7684\u5185\u5BB9\u5916\uFF0C\u8FD8\u628A\u4FEE\u6539\u65F6\u95F4\u548C\u8BBF\u95EE\u6743\u9650\u4E5F\u590D\u5236\u5230\u65B0\u6587\u4EF6\u4E2D\u3002</p><p><strong>-r</strong>\uFF1A\u6587\u4EF6\u5939\u590D\u5236</p><p>\u82E5\u7ED9\u51FA\u7684\u6E90\u6587\u4EF6\u662F\u4E00\u4E2A\u76EE\u5F55\u6587\u4EF6\uFF0C\u6B64\u65F6\u5C06\u590D\u5236\u8BE5\u76EE\u5F55\u4E0B\u6240\u6709\u7684\u5B50\u76EE\u5F55\u548C\u6587\u4EF6\u3002</p><p><strong>-l</strong>\uFF1A\u521B\u5EFA\u94FE\u63A5</p><p>\u4E0D\u590D\u5236\u6587\u4EF6\uFF0C\u53EA\u662F\u751F\u6210\u94FE\u63A5\u6587\u4EF6\u3002</p><p>\u53EA\u5728\u90E8\u5206\u7CFB\u7EDF\u6709\u6548</p><p>\u5728 Ubuntu \u4E0B\u6CA1\u6709\u6548\u679C</p><h3 id="rm\u547D\u4EE4" tabindex="-1"><a class="header-anchor" href="#rm\u547D\u4EE4" aria-hidden="true">#</a> rm\u547D\u4EE4</h3><p>\u547D\u4EE4 remove \u7684\u7F29\u5199\uFF0C\u5220\u9664</p><p>\u8865\u5145\u547D\u4EE4\uFF1A</p><p>chmod [-r] 6777\uFF08\u516B\u8FDB\u5236\u6570\uFF09 \u6587\u4EF6/\u6587\u4EF6\u5939</p><p>110(\u63D0\u6743/\u6539\u7EC4) 111\uFF08\u8BFB\u5199\u6267\u884C\uFF09 111\uFF08\u5F53\u524D\u7528\u6237\uFF09 111\uFF08\u5176\u4ED6\u7528\u6237\uFF09</p><p><strong>-i</strong> <strong>\u5220\u9664\u786E\u8BA4</strong></p><p>\u6BCF\u4E2A\u88AB\u5220\u9664\u7684\u6587\u4EF6\u90FD\u9700\u8981\u786E\u8BA4</p><p><strong>-f</strong> <strong>\u5F3A\u5236\u5220\u9664</strong></p><p>\u65E0\u9700\u786E\u8BA4\u5C31\u4F1A\u5220\u9664\u6307\u5B9A\u7684\u6587\u4EF6</p><p><strong>-r</strong> <strong>\u76EE\u5F55\u5220\u9664</strong></p><p>\u5220\u9664\u6307\u5B9A\u6587\u4EF6\u5939\u4E0B\u7684\u6240\u6709\u6587\u4EF6\u548C\u5B50\u6587\u4EF6\u5939</p><h2 id="\u5F00\u53D1\u73AF\u5883\u642D\u5EFA" tabindex="-1"><a class="header-anchor" href="#\u5F00\u53D1\u73AF\u5883\u642D\u5EFA" aria-hidden="true">#</a> \u5F00\u53D1\u73AF\u5883\u642D\u5EFA</h2><h3 id="gcc\u5B89\u88C5" tabindex="-1"><a class="header-anchor" href="#gcc\u5B89\u88C5" aria-hidden="true">#</a> gcc\u5B89\u88C5</h3><p>\u547D\u4EE4\uFF1A</p><p>1 \u8BBE\u7F6E root \u5BC6\u7801\uFF1Asudo passwd root</p><p>\u6CE8\u610F\uFF0C\u8BF7\u8BB0\u4F4F\u8FD9\u4E2A\u5BC6\u7801\uFF0C\u540E\u9762\u8FD8\u9700\u8981\u4F7F\u7528</p><p>2 \u8FDB\u5165 root \u8D26\u6237 su</p><p>3 \u5B89\u88C5\u7F16\u8BD1\u5668\uFF1Aapt-get install gcc g++</p><p>4 \u67E5\u770B\u5F53\u524D\u7684 gcc g++\u7248\u672C</p><p>gcc --version</p><p>g++ --version</p><p>5 \u9A8C\u8BC1\u4E00\u4E0B</p><p>g++ -o test main.cpp</p><p>./test</p><h3 id="ssh\u670D\u52A1\u7684\u5B89\u88C5" tabindex="-1"><a class="header-anchor" href="#ssh\u670D\u52A1\u7684\u5B89\u88C5" aria-hidden="true">#</a> ssh\u670D\u52A1\u7684\u5B89\u88C5</h3><p>\u8FD9\u4E2A\u670D\u52A1\u7528\u6237\u540E\u7EED\u7684\u4EE3\u7801\u7F16\u5199\u548C\u8FDC\u7A0B\u8FD0\u884C\u3001\u8C03\u8BD5\u547D\u4EE4\uFF1A</p><p>1 \u5B89\u88C5\u670D\u52A1\u7A0B\u5E8F\uFF1Asudo apt install openssh-server</p><p>2 \u5B89\u88C5\u5BA2\u6237\u7AEF\u7A0B\u5E8F\uFF1Asudo apt install openssh-client</p><p>3 \u4FEE\u6539\u914D\u7F6E\u6587\u4EF6\uFF1A/etc/ssh/sshd_config</p><p>LoginGraceTime 2m</p><p><u>PermitRootLogin yes</u></p><p>PubkeyAuthentication yes</p><p>PasswordAuthentication yes</p><p>ChallengeResponseAuthentication no</p><p>UsePAM yes</p><p>X11Forwarding yes</p><p>PrintMotd no</p><p>AcceptEnv LANG LC_*</p><p>Subsystem sftp /usr/lib/openssh/sftp-server</p><p>\u4E0B\u5212\u7EBF\u5185\u5BB9\u662F\u8981\u4FEE\u6539\u7684\u5730\u65B9</p><p>\u5176\u4ED6\u5730\u65B9\u8BF7\u81EA\u884C\u6BD4\u5BF9</p><p>\u5982\u679C\u4E0D\u4E00\u81F4\uFF0C\u8BF7\u53C2\u8003\u4E0A\u9762\u7684\u6587\u6863</p><p>4 \u542F\u52A8\u670D\u52A1</p><p>\u53EF\u4EE5\u76F4\u63A5\u8F93\u5165\u547D\u4EE4\u884C\uFF1A</p><p>C:\\Windows\\System32\\bash.exe -c &quot;sudo service ssh start&quot;</p><p>\u8FDB\u884C\u542F\u52A8</p><p>\u4E5F\u53EF\u4EE5\u5EFA\u7ACB\u4E00\u4E2A bat \u6587\u4EF6</p><p>\u5C06\u4E0A\u9762\u8FD9\u4E2A\u547D\u4EE4\u5199\u5165\u5176\u4E2D</p><p>\u7136\u540E\u653E\u5165\u6587\u4EF6\u5939</p><p>C:\\ProgramData\\Microsoft\\Windows\\Start Menu\\Programs\\StartUp</p><p>\u6216\u8005</p><p>C:\\Users\\\u4F60\u7684\u7528\u6237\u540D\\AppData\\Roaming\\Microsoft\\Windows\\Start Menu\\Programs\\Startup</p><p>\u70B9\u51FB\u5F00\u59CB\u83DC\u5355\uFF0C\u5C06\u9F20\u6807\u505C\u5728\u7528\u6237\u540D\u56FE\u6807\u5904</p><p>\u7528\u6237\u540D\u4F1A\u81EA\u52A8\u5C55\u793A\u51FA\u6765</p><p>\u8FD9\u6837\u5F00\u673A\u540E\u5C31\u53EF\u4EE5\u81EA\u52A8\u542F\u52A8 ssh \u670D\u52A1\u4E86</p>',180);function s(o,a){return t}var i=p(n,[["render",s],["__file","\u6613\u9053\u4E91-Linux\u7CFB\u7EDF\u547D\u4EE4.html.vue"]]);export{i as default};
